DELIMITER ;;
CREATE DEFINER=`root`@`%` PROCEDURE `AutoGenerateSeats`()
BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE r_id INT;
    DECLARE total INT;
    DECLARE i INT;
    DECLARE current_row CHAR(1);
    DECLARE seat_num INT;
    DECLARE type_id INT;
    
    -- Quét danh sách phòng chiếu mới
    DECLARE cur CURSOR FOR SELECT id, total_seats FROM `rooms` WHERE id BETWEEN 20 AND 50;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    -- Dọn sạch ghế cũ của các phòng này để tránh trùng lặp vị trí
    DELETE FROM `seats` WHERE `room_id` BETWEEN 20 AND 50;

    OPEN cur;

    read_loop: LOOP
        FETCH cur INTO r_id, total;
        IF done THEN
            LEAVE read_loop;
        END IF;

        SET i = 1;
        WHILE i <= total DO
            -- Sắp xếp mỗi hàng cố định 10 ghế
            SET seat_num = ((i - 1) % 10) + 1;
            SET current_row = CHAR(65 + FLOOR((i - 1) / 10)); 
            
            -- Thuật toán phân bổ tỷ lệ mới:
            -- 1. Từ 0% đến 60%: Ghế thường (ID: 1)
            IF i <= FLOOR(total * 0.60) THEN
                SET type_id = 1; 
            -- 2. Từ 60% đến 90%: Ghế VIP (ID: 2) (Chiếm 30% để phủ kín phòng)
            ELSEIF i <= FLOOR(total * 0.90) THEN
                SET type_id = 2; 
            -- 3. Từ 90% đến 100%: Ghế đôi Couple (ID: 3) (Đạt chuẩn 10% hàng cuối)
            ELSE
                SET type_id = 3; 
            END IF;

            INSERT IGNORE INTO `seats` (`room_id`, `seat_row`, `seat_number`, `seat_type_id`, `status`)
            VALUES (r_id, current_row, seat_num, type_id, 'active');

            SET i = i + 1;
        END WHILE;
    END LOOP;

    CLOSE cur;
END ;;
DELIMITER ;
