CREATE DEFINER=`root`@`%` PROCEDURE `AutoGenerateShowtimes`()
BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE r_id INT;
    DECLARE current_date_var DATE;
    DECLARE num_shows INT;
    DECLARE i INT;
    DECLARE rand_movie_id INT;
    DECLARE start_time_var TIME;
    DECLARE price_var DECIMAL(10,2);
    
    -- Khai báo con trỏ lấy danh sách phòng chiếu mới từ 20 đến 50
    DECLARE cur CURSOR FOR SELECT id FROM `rooms` WHERE id BETWEEN 20 AND 50;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    OPEN cur;

    read_loop: LOOP
        FETCH cur INTO r_id;
        IF done THEN
            LEAVE read_loop;
        END IF;

        -- Vòng lặp chạy qua từng ngày từ 16/05/2026 đến 20/05/2026
        SET current_date_var = '2026-05-16';
        WHILE current_date_var <= '2026-05-20' DO
            
            -- Ngẫu nhiên mỗi phòng có 3 hoặc 4 suất chiếu trong ngày
            SET num_shows = FLOOR(3 + (RAND() * 2));
            SET i = 1;
            
            WHILE i <= num_shows DO
                -- 1. Lấy ngẫu nhiên 1 mã phim (movie_id) đang có trong bảng movies
                SELECT id INTO rand_movie_id FROM `movies` ORDER BY RAND() LIMIT 1;
                
                -- 2. Phân bổ khung giờ chiếu cố định theo số thứ tự suất để tránh trùng giờ trong phòng
                IF i = 1 THEN SET start_time_var = '09:00:00';
                ELSEIF i = 2 THEN SET start_time_var = '13:00:00';
                ELSEIF i = 3 THEN SET start_time_var = '16:30:00';
                ELSE SET start_time_var = '20:00:00';
                END IF;
                
                -- 3. Đặt giá vé ngẫu nhiên từ 70,000đ đến 90,000đ tùy suất chiếu
                SET price_var = ELT(FLOOR(1 + (RAND() * 3)), 70000.00, 80000.00, 90000.00);

                -- 4. Chèn dữ liệu vào bảng showtimes
                -- Lưu ý: Bạn kiểm tra lại tên các cột (show_date, show_time, ticket_price, movie_id, room_id) 
                -- trong bảng showtimes của bạn xem có khớp 100% không nhé.
                INSERT IGNORE INTO `showtimes` (`movie_id`, `room_id`, `show_date`, `show_time`, `ticket_price`, `status`)
                VALUES (rand_movie_id, r_id, current_date_var, start_time_var, price_var, 'active');

                SET i = i + 1;
            END WHILE;
            
            -- Tăng thêm 1 ngày
            SET current_date_var = DATE_ADD(current_date_var, INTERVAL 1 DAY);
        END WHILE;
    END LOOP;

    CLOSE cur;
END ;;
DELIMITER ;
