        SET current_date_var = '2026-05-16';
        WHILE current_date_var <= '2026-05-20' DO
            
            -- Ngẫu nhiên sinh ra từ 3 đến 4 suất chiếu cho mỗi phòng trong ngày
            SET num_shows = FLOOR(3 + (RAND() * 2));
            SET i = 1;
            
            WHILE i <= num_shows DO
                -- 1. Lấy ngẫu nhiên một bộ phim hoạt động và thời lượng (duration) của phim đó
                SELECT id, duration INTO rand_movie_id, rand_duration FROM `movies` WHERE is_deleted = 0 ORDER BY RAND() LIMIT 1;
                
                -- 2. Phân bổ các khung giờ bắt đầu cố định để các suất trong phòng không bị chồng chéo giờ
                IF i = 1 THEN SET start_time_str = '08:30:00';
                ELSEIF i = 2 THEN SET start_time_str = '12:15:00';
                ELSEIF i = 3 THEN SET start_time_str = '16:00:00';
                ELSE SET start_time_str = '19:45:00';
                END IF;
                
                -- 3. Ghép ngày và giờ thành định dạng DATETIME hoàn chỉnh
                SET show_datetime = CAST(CONCAT(current_date_var, ' ', start_time_str) AS DATETIME);
                
                -- 4. Tự động tính toán giờ kết thúc phim dựa trên số phút duration của bảng movies
                SET end_datetime = DATE_ADD(show_datetime, INTERVAL rand_duration MINUTE);
                
                -- 5. Định giá vé ngẫu nhiên cho suất chiếu
                SET price_var = ELT(FLOOR(1 + (RAND() * 3)), 75000.00, 80000.00, 90000.00);

                -- 6. Chèn trực tiếp vào bảng slots thực tế của hệ thống
                INSERT IGNORE INTO `slots` 
                (`movie_id`, `room_id`, `show_time`, `end_time`, `price`, `empty_seats`, `create_at`, `is_deleted`, `couple_price`, `vip_price`)
                VALUES 
                (rand_movie_id, r_id, show_datetime, end_datetime, price_var, r_seats, NOW(), 0, 200000.00, 110000.00);

                SET i = i + 1;
            END WHILE;
            
            SET current_date_var = DATE_ADD(current_date_var, INTERVAL 1 DAY);
        END WHILE;
    END LOOP;

    CLOSE cur;
END ;;
